  "title": "उद्धरण एस्केपिंग",
  "group": "वार्म‑अप: एस्केपिंग",
  "options": [
    {
      "text": "echo 'It's 🔨 Time!'"
    },
    {
      "text": "echo 'It\\\\'s 🔨 Time!'"
    },
    {
      "text": "echo 'It'\\\\''s 🔨 Time!'"
    },
    {
      "text": "echo 'It''s 🔨 Time!'"
    },
    {
      "text": "Error"
    }
  ],
  "questionProse": [
    "_`It's 🔨 Time!` को क्या प्रिंट करेगा?_"
  ],
  "explanationProse": [
    "मैं जानता हूँ। यह पागलपन है कि एस्केपिंग कितनी जल्दी स्ट्रिंग्स को पढ़ने में कठिन बना देती है। सोचो Bash स्ट्रिंग्स में अन्य भाषाओं को एस्केप करना - उन सभी कोट्स, अपॉस्ट्रोफ़ और `$` सिंबल्स के साथ जो तुम्हें गड़बड़ कर देंगे। 🫠\n\n    सिंगल कोट्स को सिंगल‑कोटेड स्ट्रिंग्स के अंदर एस्केप करना पड़ता है। क्लोज‑कोट, एस्केप‑कोट, री‑ओपन‑कोट क्रम (`'\\''`) आउटपुट देता है:",
    "इसे संभालने के और भी तरीके हैं, लेकिन यह सबसे आम है।"
  ]
}
